package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetRecordSeparator() {
        // Create a mock CSVFormat object
        CSVFormat csvFormat = mock(CSVFormat.class);

        // Set the expected record separator
        String expectedRecordSeparator = "\r\n";
        when(csvFormat.getRecordSeparator()).thenReturn(expectedRecordSeparator);

        // Verify the getRecordSeparator method
        assertEquals(expectedRecordSeparator, csvFormat.getRecordSeparator());
    }
}
